init_logger();
async function searchNode(state) {
  logger_default.info("[SearchNode] Starting news search across all categories");
  try {
    const categories = state.categories.length > 0 ? state.categories : news_search_default.getAvailableCategories();
    const searchResults = await news_search_default.searchAllCategories(categories);
    let totalFound = 0;
    const rawNews = [];
    for (const [category, results] of searchResults.entries()) {
      for (const result of results) {
        if (!result.link) continue;
        const title = result.title || result.link || "Untitled";
        const snippet = result.snippet || (result.content ? result.content.slice(0, 200) : "");
        let source = "unknown";
        try {
          source = new URL(result.link).hostname;
        } catch (error) {
          logger_default.debug(`[SearchNode] Failed to parse source for ${result.link}`);
        }
        rawNews.push({
          id: crypto.randomUUID(),
          title,
          content: result.content,
          source,
          url: result.link,
          publishedAt: result.date ? new Date(result.date) : /* @__PURE__ */ new Date(),
          categories: [category],
          tags: [],
          sentiment: "NEUTRAL",
          importance: "MEDIUM",
          snippet,
          scrapedAt: /* @__PURE__ */ new Date(),
          createdAt: /* @__PURE__ */ new Date()
        });
      }
      totalFound += results.length;
      logger_default.info(`[SearchNode] ${category}: Found ${results.length} results`);
    }
    const byCategory = {
      ...state.stats.byCategory
    };
    for (const category of categories) {
      byCategory[category] = searchResults.get(category)?.length || 0;
    }
    const queryPlan = news_search_default.getLastQueryPlan();
    const querySummary = Array.from(queryPlan.entries()).map(([category, queries]) => `${category}: ${queries.join(" | ")}`).join(" ; ");
    const trimmedSummary = querySummary.length > 400 ? `${querySummary.slice(0, 400)}...` : querySummary;
    const thoughts = [
      ...state.thoughts,
      `Searched ${categories.length} categories, found ${totalFound} total results`,
      `Results by category: ${Array.from(searchResults.entries()).map(([k, v]) => `${k}: ${v.length}`).join(", ")}`,
      trimmedSummary ? `Queries used: ${trimmedSummary}` : ""
    ].filter(Boolean);
    return {
      currentStep: "SEARCH_COMPLETE",
      searchResults,
      rawNews,
      stats: {
        ...state.stats,
        totalFound,
        byCategory
      },
      thoughts
    };
  } catch (error) {
    logger_default.error("[SearchNode] Failed to search news:", error);
    return {
      currentStep: "SEARCH_ERROR",
      errors: [
        ...state.errors,
        `Search failed: ${error}`
      ]
    };
  }
}

