init_logger();
async function storeNode(state) {
  logger_default.info(`[StoreNode] Storing ${state.categorizedNews.length} articles in news store`);
  if (state.categorizedNews.length === 0) {
    return {
      currentStep: "STORE_SKIPPED",
      stats: {
        ...state.stats,
        totalStored: 0,
        totalDuplicates: 0
      },
      thoughts: [...state.thoughts, "No articles to store"]
    };
  }
  try {
    const { stored, duplicates } = await news_store_default.storeNews(state.categorizedNews);
    logger_default.info(`[StoreNode] Stored ${stored.length} articles, skipped ${duplicates.length} duplicates`);
    const storedSet = new Set(stored);
    const storedArticles = state.categorizedNews.filter((article) => storedSet.has(article.id));
    return {
      currentStep: "STORE_COMPLETE",
      categorizedNews: storedArticles,
      storedCount: stored.length,
      duplicateCount: duplicates.length,
      stats: {
        ...state.stats,
        totalStored: stored.length,
        totalDuplicates: duplicates.length
      },
      thoughts: [
        ...state.thoughts,
        `Stored ${stored.length} new articles in news database`,
        duplicates.length > 0 ? `Skipped ${duplicates.length} duplicate URLs` : ""
      ].filter(Boolean)
    };
  } catch (error) {
    logger_default.error("[StoreNode] Failed to store news:", error);
    return {
      currentStep: "STORE_ERROR",
      errors: [
        ...state.errors,
        `Store failed: ${error}`
      ]
    };
  }
}

