  // ENHANCEMENT 9: Anomaly Detection
  // ============================================================
  /**
   * Detect anomalies in cluster heat patterns
   */
  async detectHeatAnomalies(clusterId) {
    await this.initialize();
    if (!this.db) {
      return { clusterId, isAnomaly: false, anomalyScore: 0, detectedAt: /* @__PURE__ */ new Date() };
    }
    try {
      const history = await this.getHeatHistory(clusterId, 24);
      if (history.length < 5) {
        return { clusterId, isAnomaly: false, anomalyScore: 0, detectedAt: /* @__PURE__ */ new Date() };
      }
      const heats = history.map((h2) => h2.heatScore);
      const mean = heats.reduce((a, b) => a + b, 0) / heats.length;
      const stdDev = Math.sqrt(heats.reduce((sq, n) => sq + Math.pow(n - mean, 2), 0) / heats.length);
      const currentHeat = heats[0];
      const zScore = stdDev > 0 ? (currentHeat - mean) / stdDev : 0;
      let isAnomaly = false;
      let anomalyType;
      let anomalyScore = Math.abs(zScore);
      if (zScore > 3) {
        isAnomaly = true;
        anomalyType = "SUDDEN_SPIKE";
      } else if (zScore < -3) {
        isAnomaly = true;
        anomalyType = "SUDDEN_DROP";
      }
      const velocities = history.map((h2) => h2.velocity);
      const avgVelocity = velocities.reduce((a, b) => a + b, 0) / velocities.length;
      const currentVelocity = velocities[0];
      if (Math.abs(currentVelocity - avgVelocity) > 2 * stdDev) {
        isAnomaly = true;
        anomalyType = anomalyType || "VELOCITY_ANOMALY";
        anomalyScore = Math.max(anomalyScore, Math.abs(currentVelocity - avgVelocity) / stdDev);
      }
      const detection = {
        clusterId,
        isAnomaly,
        anomalyType,
        anomalyScore,
        detectedAt: /* @__PURE__ */ new Date()
      };
      if (isAnomaly) {
        this.db.prepare(`
                    UPDATE story_clusters
                    SET is_anomaly = 1,
                        anomaly_type = ?,
                        anomaly_score = ?
                    WHERE id = ?
                `).run(anomalyType, anomalyScore, clusterId);
      } else {
        this.db.prepare(`
                    UPDATE story_clusters
                    SET is_anomaly = 0,
                        anomaly_type = NULL,
                        anomaly_score = 0
                    WHERE id = ?
                `).run(clusterId);
      }
      return detection;
    } catch (error) {
      logger_default.error("[StoryClusterStoreEnhanced] Failed to detect anomalies:", error);
      return { clusterId, isAnomaly: false, anomalyScore: 0, detectedAt: /* @__PURE__ */ new Date() };
    }
  }
